import React, { useState, useMemo } from "react";
import { Card, Typography, Row, Col, Space, Breadcrumb, theme, Alert, Select, Button } from "antd";
import { DotChartOutlined, HomeOutlined, InfoCircleOutlined, FilterOutlined, DownloadOutlined } from "@ant-design/icons";
import EChart from "@/framework/components/Chart/EChart";
import { useI18n } from "@/framework/i18n/hooks";
import { mockStorages } from "../../dashboard/data/mockData";
import { faker } from "@faker-js/faker";

const { Title, Paragraph } = Typography;

export default function StatCorrelationPage() {
  const { t } = useI18n(["storageLocker", "common"]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const { option, stats } = useMemo(() => {
    const targets = selectedIds.length > 0 ? selectedIds.length : 5;
    const data = Array.from({ length: 20 * targets }, () => [
      faker.number.float({ min: 5, max: 35 }), // Temp
      faker.number.float({ min: 10, max: 300 }) // Usage
    ]);

    return {
      stats: {
        r: faker.number.float({ min: 0.7, max: 0.95, precision: 0.01 }),
        p: "< 0.001",
        n: 100 * targets
      },
      option: {
        tooltip: { trigger: "item" },
        legend: { top: 0, left: "center", orient: "horizontal" },
        grid: { top: 40 },
        xAxis: { name: t("storageLocker:statistics.correlation.temp") },
        yAxis: { name: t("storageLocker:statistics.correlation.usageCount") },
        series: [
          {
            symbolSize: 10,
            data: data,
            type: "scatter",
            itemStyle: { opacity: 0.6 }
          }
        ]
      }
    };
  }, [selectedIds]);

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24 }}>
      <Breadcrumb
        items={[
          { title: <HomeOutlined />, href: "/" },
          { title: t("storageLocker:navigation.statistics") },
          { title: t("storageLocker:navigation.statCorrelation") },
        ]}
      />

      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[16, 16]} align="middle">
          <Col md={8} lg={6}>
            <Title level={4} style={{ margin: 0 }}>
              <DotChartOutlined style={{ marginRight: 8, color: "#f5222d" }} />
              {t("storageLocker:navigation.statCorrelation")}
            </Title>
          </Col>
          <Col flex="auto">
            <Row gutter={16} justify="end">
              <Col span={10}>
                <Select 
                  mode="multiple"
                  placeholder={t("storageLocker:dashboard.selectPlaceholder")}
                  style={{ width: "100%" }}
                  maxTagCount="responsive"
                  value={selectedIds}
                  onChange={setSelectedIds}
                  options={mockStorages.map(s => ({ label: s.name, value: s.id }))}
                  allowClear
                />
              </Col>
              <Col>
                <Space>
                  <Button type="primary" icon={<FilterOutlined />}>{t("common:search")}</Button>
                  <Button icon={<DownloadOutlined />}>{t("common:exportXlsx")}</Button>
                </Space>
              </Col>
            </Row>
          </Col>
        </Row>
      </Card>
      
      <Card bordered={false} style={{ flex: 1, boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Alert
          message={t("storageLocker:statistics.correlation.insight")}
          description={t("storageLocker:statistics.correlation.insightDesc")}
          type="info"
          showIcon
          icon={<InfoCircleOutlined />}
          style={{ marginBottom: 20 }}
        />
        <Row gutter={24}>
          <Col span={16}>
            <EChart option={option} style={{ height: 450 }} />
          </Col>
          <Col span={8}>
            <Card title={t("storageLocker:statistics.correlation.summary")} size="small">
              <Paragraph><b>{t("storageLocker:statistics.correlation.coeff")}:</b> {stats.r}</Paragraph>
              <Paragraph><b>{t("storageLocker:statistics.correlation.pValue")}:</b> {stats.p}</Paragraph>
              <Paragraph><b>{t("storageLocker:statistics.correlation.sampleSize")}:</b> {stats.n}</Paragraph>
              <Paragraph><b>{t("storageLocker:statistics.correlation.keyDriver")}:</b> {t("storageLocker:statistics.correlation.temp")}</Paragraph>
            </Card>
          </Col>
        </Row>
      </Card>
    </div>
  );
}
